3998	\begin{lemma}[Quasi-coherence datum: a cover with a presentation on each member]
3999	  \label{lem:quasicoherentData_mathlib}
4000	  \lean{SheafOfModules.QuasicoherentData}
4001	  \mathlibok
4002	  \textit{Provided by Mathlib.}
4003	  A \emph{quasi-coherence datum} for a sheaf of modules \(\mathcal{F}\) consists of a family of objects
4004	  \(U_i\) of the site that covers the terminal object, together with, for each \(i\), a presentation of
4005	  the over-picture restriction \(\mathcal{F}.\operatorname{over} U_i\). A sheaf of modules is
4006	  quasi-coherent precisely when such a datum exists.
4007	\end{lemma}
