4009	\begin{lemma}[Sections of a restricted module are sections over the image open]
4010	  \label{lem:restrict_obj_mathlib}
4011	  \lean{AlgebraicGeometry.Scheme.Modules.restrict_obj}
4012	  \mathlibok
4013	  \textit{Provided by Mathlib.}
4014	  For an \(\mathcal{O}_Y\)-module \(\mathcal{M}\), an open immersion \(\iota : X \to Y\), and an open
4015	  \(U \subseteq X\), the sections of the restricted module over \(U\) coincide definitionally with the
4016	  sections of \(\mathcal{M}\) over the image open \(\iota(U)\):
4017	  \(\Gamma(\mathcal{M}.\operatorname{restrict} \iota, U) = \Gamma(\mathcal{M}, \iota(U))\), and
4018	  likewise for the restriction maps. The section comparison is therefore an equality, not merely an
4019	  isomorphism.
4020	\end{lemma}
